    private fun item(id: String, name: String, category: PlotterSvgCategory, tags: String, body: String): PlotterSvgItem =
        PlotterSvgItem(
            id = id,
            name = name,
            category = category,
            tags = tags.split(" ").filter { it.isNotBlank() },
            source = "Iconify / Material Design Icons (Apache-2.0)",
            svg = svg(body),
        )

    private fun svg(body: String): String =
        """<svg xmlns="http://www.w3.org/2000/svg" width="80mm" height="80mm" viewBox="0 0 24 24">$body</svg>"""
